            return Base64.getEncoder().encodeToString(signature.sign());
        } catch (GeneralSecurityException e) {
            throw new IllegalStateException("Failed to sign payload", e);
        }
    }

    public boolean verify(String payload, String encodedSignature, PublicKey publicKey) {
        try {
            Signature verifier = Signature.getInstance("SHA256withRSA");
            verifier.initVerify(publicKey);
            verifier.update(payload.getBytes(StandardCharsets.UTF_8));
            return verifier.verify(Base64.getDecoder().decode(encodedSignature));
        } catch (GeneralSecurityException e) {
            throw new IllegalStateException("Failed to verify payload", e);
        }
    }

    public String wrapKey(byte[] key, PublicKey publicKey) {
        try {
            Cipher cipher = Cipher.getInstance("RSA/ECB/OAEPWithSHA-256AndMGF1Padding");
            cipher.init(Cipher.ENCRYPT_MODE, publicKey);
            return Base64.getEncoder().encodeToString(cipher.doFinal(key));
        } catch (GeneralSecurityException e) {
            throw new IllegalStateException("Failed to wrap key", e);
        }
    }

    public byte[] unwrapKey(String wrappedKey, PrivateKey privateKey) {
        try {
            Cipher cipher = Cipher.getInstance("RSA/ECB/OAEPWithSHA-256AndMGF1Padding");
            cipher.init(Cipher.DECRYPT_MODE, privateKey);
            return cipher.doFinal(Base64.getDecoder().decode(wrappedKey));
        } catch (GeneralSecurityException e) {
            throw new IllegalStateException("Failed to unwrap key", e);
        }
    }

    public static byte[] generateRandomBytes(int size) {
        byte[] bytes = new byte[size];
        new SecureRandom().nextBytes(bytes);
        return bytes;
    }

    public void encryptStream(InputStream source, OutputStream destination, byte[] key) {
        try {
            byte[] iv = generateRandomBytes(IV_SIZE);
            destination.write(iv);
            Cipher cipher = Cipher.getInstance(AES_GCM);
            cipher.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(key, AES_ALGO), new GCMParameterSpec(GCM_TAG_BITS, iv));
            try (CipherOutputStream encrypted = new CipherOutputStream(destination, cipher)) {
                source.transferTo(encrypted);
            }
        } catch (GeneralSecurityException | IOException e) {
            throw new IllegalStateException("Failed to encrypt stream", e);
        }
    }

    public void decryptStream(InputStream source, OutputStream destination, byte[] key) {
        try {
            byte[] iv = source.readNBytes(IV_SIZE);
            if (iv.length != IV_SIZE) {
                throw new IllegalStateException("Invalid encrypted stream header");
            }
            Cipher cipher = Cipher.getInstance(AES_GCM);
            cipher.init(Cipher.DECRYPT_MODE, new SecretKeySpec(key, AES_ALGO), new GCMParameterSpec(GCM_TAG_BITS, iv));
            try (CipherInputStream decrypted = new CipherInputStream(source, cipher)) {
                decrypted.transferTo(destination);
            }
        } catch (GeneralSecurityException | IOException e) {
            throw new IllegalStateException("Failed to decrypt stream", e);
        }
    }
}

package com.securemsg.security;

import java.security.KeyPair;
import java.security.KeyPairGenerator;
import java.security.KeyFactory;
import java.security.NoSuchAlgorithmException;
import java.security.PrivateKey;
import java.security.PublicKey;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.PKCS8EncodedKeySpec;
import java.security.spec.X509EncodedKeySpec;
import java.util.Base64;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class InMemoryKeyVault implements KeyVault {
    private final Map<String, KeyPair> signingKeys = new ConcurrentHashMap<>();
    private final Map<String, byte[]> encryptionKeys = new ConcurrentHashMap<>();

    @Override
    public KeyPair getOrCreateSigningKeyPair(String ownerId) {
        return signingKeys.computeIfAbsent(ownerId, ignored -> {
            try {
                KeyPairGenerator generator = KeyPairGenerator.getInstance("RSA");
                generator.initialize(3072);
                return generator.generateKeyPair();
            } catch (NoSuchAlgorithmException e) {
                throw new IllegalStateException("RSA algorithm is not available", e);
            }
        });
    }

    @Override
    public byte[] getOrCreateEncryptionKey(String ownerId) {
        return encryptionKeys.computeIfAbsent(ownerId,
                ignored -> Base64.getDecoder().decode(Base64.getEncoder().encodeToString(CryptoService.generateRandomBytes(32))));
    }

    @Override
    public void rotateEncryptionKey(String ownerId) {
        encryptionKeys.put(ownerId, CryptoService.generateRandomBytes(32));
    }

    @Override
    public String exportPublicKey(String ownerId) {
        KeyPair pair = getOrCreateSigningKeyPair(ownerId);
        return Base64.getEncoder().encodeToString(pair.getPublic().getEncoded());
    }

    @Override
    public String exportPrivateKey(String ownerId) {
        KeyPair pair = getOrCreateSigningKeyPair(ownerId);
        return Base64.getEncoder().encodeToString(pair.getPrivate().getEncoded());
    }

    @Override
    public void importSigningKeyPair(String ownerId, String base64PublicKey, String base64PrivateKey) {
        try {
            KeyFactory keyFactory = KeyFactory.getInstance("RSA");
            PublicKey publicKey = keyFactory.generatePublic(new X509EncodedKeySpec(Base64.getDecoder().decode(base64PublicKey)));
            PrivateKey privateKey = keyFactory.generatePrivate(new PKCS8EncodedKeySpec(Base64.getDecoder().decode(base64PrivateKey)));
            signingKeys.put(ownerId, new KeyPair(publicKey, privateKey));
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            throw new IllegalStateException("Failed to import key pair", e);
        }
    }
}

package com.securemsg.security;

import java.security.KeyPair;
import java.security.KeyPairGenerator;
import java.security.KeyFactory;
import java.security.NoSuchAlgorithmException;
import java.security.PrivateKey;
import java.security.PublicKey;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.PKCS8EncodedKeySpec;
import java.security.spec.X509EncodedKeySpec;
import java.util.Base64;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class InMemoryKeyVault implements KeyVault {
    private final Map<String, KeyPair> signingKeys = new ConcurrentHashMap<>();
    private final Map<String, byte[]> encryptionKeys = new ConcurrentHashMap<>();

    @Override
    public KeyPair getOrCreateSigningKeyPair(String ownerId) {
        return signingKeys.computeIfAbsent(ownerId, ignored -> generateSigningKeyPair());
    }

    @Override
    public void rotateSigningKeyPair(String ownerId) {
        signingKeys.put(ownerId, generateSigningKeyPair());
    }

    @Override
    public byte[] getOrCreateEncryptionKey(String ownerId) {
        return encryptionKeys.computeIfAbsent(ownerId,
                ignored -> Base64.getDecoder().decode(Base64.getEncoder().encodeToString(CryptoService.generateRandomBytes(32))));
    }

    @Override
    public void rotateEncryptionKey(String ownerId) {
        encryptionKeys.put(ownerId, CryptoService.generateRandomBytes(32));
    }

    @Override
    public String exportPublicKey(String ownerId) {
        KeyPair pair = getOrCreateSigningKeyPair(ownerId);
        return Base64.getEncoder().encodeToString(pair.getPublic().getEncoded());
    }

    @Override
    public String exportPrivateKey(String ownerId) {
        KeyPair pair = getOrCreateSigningKeyPair(ownerId);
        return Base64.getEncoder().encodeToString(pair.getPrivate().getEncoded());
    }

    @Override
    public void importSigningKeyPair(String ownerId, String base64PublicKey, String base64PrivateKey) {
        try {
            KeyFactory keyFactory = KeyFactory.getInstance("RSA");
            PublicKey publicKey = keyFactory.generatePublic(new X509EncodedKeySpec(Base64.getDecoder().decode(base64PublicKey)));
            PrivateKey privateKey = keyFactory.generatePrivate(new PKCS8EncodedKeySpec(Base64.getDecoder().decode(base64PrivateKey)));
            signingKeys.put(ownerId, new KeyPair(publicKey, privateKey));
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            throw new IllegalStateException("Failed to import key pair", e);
        }
    }

    private KeyPair generateSigningKeyPair() {
        try {
            KeyPairGenerator generator = KeyPairGenerator.getInstance("RSA");
            generator.initialize(3072);
            return generator.generateKeyPair();
        } catch (NoSuchAlgorithmException e) {
            throw new IllegalStateException("RSA algorithm is not available", e);
        }
    }
}

