        User updated = existing.withRole(role);
        usersByLogin.put(login, updated);
        auditService.record("ROLE_ASSIGNED", login, "Role set to " + role);
        return updated;
    }

    public User rotateHardwareToken(String login) {
        User existing = requireUser(login);
        User updated = existing.withHardwareTokenSecret(generateHardwareToken());
        usersByLogin.put(login, updated);
        auditService.record("HARDWARE_TOKEN_ROTATED", login, "Token rotated");
        return updated;
    }

    public User block(String login, String reason) {
        User existing = requireUser(login);
        User updated = existing.withStatus(UserStatus.BLOCKED);
        usersByLogin.put(login, updated);
        auditService.record("USER_BLOCKED", login, reason);
        return updated;
    }

    public User recoverAfterCompromise(String login) {
        User existing = requireUser(login);
        keyVault.rotateSigningKeyPair(existing.id().toString());
        keyVault.rotateEncryptionKey(existing.id().toString());
        User recovered = existing
                .withStatus(UserStatus.ACTIVE)
                .withFailedAttempts(0)
                .withHardwareTokenSecret(generateHardwareToken());
        usersByLogin.put(login, recovered);
        auditService.record("USER_RECOVERED", login, "Credentials and keys rotated after compromise");
        return recovered;
    }

    public Optional<User> findByLogin(String login) {
        return Optional.ofNullable(usersByLogin.get(login));
    }

    private void onAuthFailure(User user, String reason) {
        int attempts = user.failedAuthAttempts() + 1;
        User updated = user.withFailedAttempts(attempts);
        if (attempts >= MAX_FAILED_AUTH_ATTEMPTS) {
            updated = updated.withStatus(UserStatus.BLOCKED);
            auditService.record("USER_AUTO_BLOCKED", user.login(), "Too many failed attempts");
        }
        usersByLogin.put(user.login(), updated);
        auditService.record("AUTH_FAILED", user.login(), reason + "; attempts=" + attempts);
    }

    private User requireUser(String login) {
        User user = usersByLogin.get(login);
        if (user == null) {
            throw new IllegalArgumentException("User not found");
        }
        return user;
    }

    private String hash(String input) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            return HexFormat.of().formatHex(digest.digest(input.getBytes(StandardCharsets.UTF_8)));
        } catch (NoSuchAlgorithmException e) {
            throw new IllegalStateException("SHA-256 algorithm is not available", e);
        }
    }

    private String generateHardwareToken() {
        return UUID.randomUUID().toString().substring(0, 8);
    }

    public User changePassword(String login, String newPassword) {
        User existing = requireUser(login);
        User updated = existing.withPasswordHash(hash(newPassword)).withFailedAttempts(0);
        usersByLogin.put(login, updated);
        auditService.record("PASSWORD_CHANGED", login, "Password changed");
        return updated;
    }
}

package com.securemsg.security;

import org.junit.jupiter.api.Test;

import java.security.KeyPair;

import static org.junit.jupiter.api.Assertions.*;

class CryptoServiceTest {
    private final CryptoService cryptoService = new CryptoService();

    @Test
    void shouldEncryptAndDecrypt() {
        byte[] key = CryptoService.generateRandomBytes(32);
        String plain = "secret message";

        String encrypted = cryptoService.encrypt(plain, key);
        String decrypted = cryptoService.decrypt(encrypted, key);

        assertNotEquals(plain, encrypted);
        assertEquals(plain, decrypted);
    }

    @Test
    void shouldSignAndVerify() {
        InMemoryKeyVault keyVault = new InMemoryKeyVault();
        KeyPair keyPair = keyVault.getOrCreateSigningKeyPair("alice");
        String payload = "payload";

        String signature = cryptoService.sign(payload, keyPair.getPrivate());

        assertTrue(cryptoService.verify(payload, signature, keyPair.getPublic()));
        assertFalse(cryptoService.verify(payload + "tampered", signature, keyPair.getPublic()));
    }
}

package com.securemsg.security;

import org.junit.jupiter.api.Test;

import java.security.KeyPair;

import static org.junit.jupiter.api.Assertions.*;

class CryptoServiceTest {
    private final CryptoService cryptoService = new CryptoService();

    @Test
    void shouldEncryptAndDecrypt() {
        byte[] key = CryptoService.generateRandomBytes(32);
        String plain = "secret message";

        String encrypted = cryptoService.encrypt(plain, key);
        String decrypted = cryptoService.decrypt(encrypted, key);

        assertNotEquals(plain, encrypted);
        assertEquals(plain, decrypted);
    }

    @Test
    void shouldSignAndVerify() {
        InMemoryKeyVault keyVault = new InMemoryKeyVault();
        KeyPair keyPair = keyVault.getOrCreateSigningKeyPair("alice");
        String payload = "payload";

        String signature = cryptoService.sign(payload, keyPair.getPrivate());

        assertTrue(cryptoService.verify(payload, signature, keyPair.getPublic()));
        assertFalse(cryptoService.verify(payload + "tampered", signature, keyPair.getPublic()));
    }

    @Test
    void shouldWrapAndUnwrapMessageKey() {
        InMemoryKeyVault keyVault = new InMemoryKeyVault();
        KeyPair keyPair = keyVault.getOrCreateSigningKeyPair("bob");
        byte[] messageKey = CryptoService.generateRandomBytes(32);

        String wrapped = cryptoService.wrapKey(messageKey, keyPair.getPublic());
        byte[] unwrapped = cryptoService.unwrapKey(wrapped, keyPair.getPrivate());

        assertArrayEquals(messageKey, unwrapped);
    }
}

package com.securemsg.service;

import com.securemsg.domain.DeliveryStatus;
import com.securemsg.domain.Message;
import com.securemsg.security.CryptoService;
import com.securemsg.security.InMemoryKeyVault;
import org.junit.jupiter.api.Test;

import java.util.List;
import java.util.UUID;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class MessagingServiceTest {

    @Test
    void shouldSendDecryptAndSyncMessages() {
        AuditService audit = new AuditService();
        MessagingService messagingService = new MessagingService(new CryptoService(), new InMemoryKeyVault(), audit);
        UUID alice = UUID.randomUUID();
        UUID bob = UUID.randomUUID();

        Message message = messagingService.send(alice, bob, "hello bob");
        messagingService.confirmDelivery(message.id());

        List<Message> bobHistory = messagingService.syncHistory(bob);
        assertEquals(1, bobHistory.size());
        assertEquals(DeliveryStatus.DELIVERED, bobHistory.getFirst().status());

        String decrypted = messagingService.decryptForRecipient(message, bob);
        assertEquals("hello bob", decrypted);
    }

    @Test
    void shouldForbidDeleteByOtherUser() {
        AuditService audit = new AuditService();
        MessagingService messagingService = new MessagingService(new CryptoService(), new InMemoryKeyVault(), audit);

        UUID alice = UUID.randomUUID();
        UUID bob = UUID.randomUUID();
        UUID eve = UUID.randomUUID();

        Message message = messagingService.send(alice, bob, "hello");

        assertThrows(SecurityException.class, () -> messagingService.deleteMessage(message.id(), eve));

        messagingService.deleteMessage(message.id(), bob);
        Message deleted = messagingService.syncHistory(bob).getFirst();
        assertTrue(deleted.status() == DeliveryStatus.DELETED);
    }
}

package com.securemsg.service;

import com.securemsg.domain.DeliveryStatus;
import com.securemsg.domain.Message;
import com.securemsg.security.CryptoService;
import com.securemsg.security.InMemoryKeyVault;
import org.junit.jupiter.api.Test;

import java.util.List;
import java.util.UUID;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class MessagingServiceTest {

    @Test
    void shouldSendDecryptAndSyncMessages() {
        AuditService audit = new AuditService();
        MessagingService messagingService = new MessagingService(new CryptoService(), new InMemoryKeyVault(), audit);
        UUID alice = UUID.randomUUID();
        UUID bob = UUID.randomUUID();

        Message message = messagingService.send(alice, bob, "hello bob");
        assertTrue(message.wrappedMessageKey() != null && !message.wrappedMessageKey().isBlank());
        messagingService.confirmDelivery(message.id());

        List<Message> bobHistory = messagingService.syncHistory(bob);
        assertEquals(1, bobHistory.size());
        assertEquals(DeliveryStatus.DELIVERED, bobHistory.getFirst().status());

        String decrypted = messagingService.decryptForRecipient(message, bob);
        assertEquals("hello bob", decrypted);
    }

    @Test
    void shouldSetErrorStatus() {
        AuditService audit = new AuditService();
        MessagingService messagingService = new MessagingService(new CryptoService(), new InMemoryKeyVault(), audit);
        UUID alice = UUID.randomUUID();
        UUID bob = UUID.randomUUID();

        Message message = messagingService.send(alice, bob, "hello");
        messagingService.markError(message.id(), "network");

        Message inHistory = messagingService.syncHistory(bob).getFirst();
        assertEquals(DeliveryStatus.ERROR, inHistory.status());
    }

    @Test
    void shouldForbidDeleteByOtherUser() {
        AuditService audit = new AuditService();
        MessagingService messagingService = new MessagingService(new CryptoService(), new InMemoryKeyVault(), audit);

        UUID alice = UUID.randomUUID();
        UUID bob = UUID.randomUUID();
        UUID eve = UUID.randomUUID();

        Message message = messagingService.send(alice, bob, "hello");

        assertThrows(SecurityException.class, () -> messagingService.deleteMessage(message.id(), eve));

        messagingService.deleteMessage(message.id(), bob);
        Message deleted = messagingService.syncHistory(bob).getFirst();
        assertTrue(deleted.status() == DeliveryStatus.DELETED);
    }
}

package com.securemsg.service;

import com.securemsg.domain.Role;
import com.securemsg.domain.User;
import com.securemsg.domain.UserStatus;
import com.securemsg.security.InMemoryKeyVault;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

class UserServiceTest {

    @Test
    void shouldAuthenticateWithTwoFactors() {
        AuditService audit = new AuditService();
        UserService users = new UserService(audit, new InMemoryKeyVault());
        User user = users.register("alice", "password", Role.USER, "token123");
        users.confirm(user.login());

        assertTrue(users.authenticate("alice", "password", "token123"));
        assertFalse(users.authenticate("alice", "password", "bad"));
    }

    @Test
    void shouldAutoBlockAfterTooManyFailedAttempts() {
        AuditService audit = new AuditService();
        UserService users = new UserService(audit, new InMemoryKeyVault());
        User user = users.register("bob", "password", Role.USER, "token456");
        users.confirm(user.login());

        for (int i = 0; i < 5; i++) {
            users.authenticate("bob", "wrong-password");
        }

        User blocked = users.findByLogin("bob").orElseThrow();
        assertEquals(UserStatus.BLOCKED, blocked.status());
    }
}

package com.securemsg.service;

import com.securemsg.domain.Role;
import com.securemsg.domain.User;
import com.securemsg.domain.UserStatus;
import com.securemsg.security.InMemoryKeyVault;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

class UserServiceTest {

    @Test
    void shouldAuthenticateWithTwoFactors() {
        AuditService audit = new AuditService();
        UserService users = new UserService(audit, new InMemoryKeyVault());
        User user = users.register("alice", "password", Role.USER, "token123");
        users.confirm(user.login());

        assertTrue(users.authenticate("alice", "password", "token123"));
        assertFalse(users.authenticate("alice", "password", "bad"));
    }

    @Test
    void shouldAutoBlockAfterTooManyFailedAttempts() {
        AuditService audit = new AuditService();
        UserService users = new UserService(audit, new InMemoryKeyVault());
        User user = users.register("bob", "password", Role.USER, "token456");
        users.confirm(user.login());

        for (int i = 0; i < 5; i++) {
            users.authenticate("bob", "wrong-password");
        }

        User blocked = users.findByLogin("bob").orElseThrow();
        assertEquals(UserStatus.BLOCKED, blocked.status());
    }

    @Test
    void shouldRecoverAfterCompromise() {
        AuditService audit = new AuditService();
        UserService users = new UserService(audit, new InMemoryKeyVault());
        User user = users.register("charlie", "password", Role.USER, "token001");
        users.confirm(user.login());
        users.block(user.login(), "incident");

        User recovered = users.recoverAfterCompromise(user.login());

        assertEquals(UserStatus.ACTIVE, recovered.status());
        assertTrue(users.authenticate("charlie", "password", recovered.hardwareTokenSecret()));
    }
}
